script:
# ========================================================
# 1️⃣ + 2️⃣ العمليات التي تتم عند إنشاء التذكرة لأول مرة فقط
# ========================================================
if doc.is_new():
    # ─── الجزء الأول: جلب بيانات الوكالة من الـ CRM ───
    sender_email = doc.raised_by

    if sender_email:
        agency_data = frappe.db.get_value(
            "Agency Contract",
            {"email": sender_email},
            ["pcc_code", "agency_name"],
            as_dict=True
        )

        if agency_data:
            doc.pcc = agency_data.pcc_code
            doc.agency_name = agency_data.agency_name
            doc.custom_agent_contact = sender_email
        else:
            doc.pcc = "Unknown"
            doc.agency_name = f"Unknown - {sender_email}"

    # ─── الجزء الثاني: نظام التوجيه التلقائي المطور ───
    subject_text = (doc.subject or "").lower()

    csm_keywords = [
        "migration", "data migration", "data transfer", "نقل بيانات", "ترحيل بيانات", "تحويل بيانات",
        "complaint", "شكوى", "delay", "تأخير", "follow up", "متابعة", "onboarding",
        "implementation", "training", "تدريب", "setup assistance", "customer success"
    ]

    finance_keywords = [
        "invoice", "billing", "payment", "refund", "subscription", "renewal", "charge", 
        "overdue", "transaction", "credit", "debit", "فاتورة", "دفع", "اشتراك",
        "تجديد", "استرداد", "مطالبة مالية", "حسابات", "مالية"
    ]

    product_keywords = [
        "bug", "error", "patch", "feature request", "enhancement", "customization", 
        "development", "integration", "api", "performance", "optimization", "ui", "ux",
        "خطأ برمجي", "مشكلة بالنظام", "تعديل", "تطوير", "برمجة", "ميزة جديدة", "تكامل"
    ]

    it_keywords = [
        "server", "network", "internet", "printer", "camera", "firewall", "telephony", 
        "3cx", "vpn", "email issue", "wifi", "router", "login", "password", "slow", 
        "crash", "down", "not working", "سيرفر", "شبكة", "انترنت", "طابعة", "كاميرا", 
        "جدار حماية", "سنترال", "فايرول", "راوتر", "واي فاي", "إيميل لا يعمل"
    ]

    csm_score = 0
    for k in csm_keywords:
        if k in subject_text:
            csm_score += 1

    finance_score = 0
    for k in finance_keywords:
        if k in subject_text:
            finance_score += 1

    product_score = 0
    for k in product_keywords:
        if k in subject_text:
            product_score += 1

    it_score = 0
    for k in it_keywords:
        if k in subject_text:
            it_score += 1

    priority = ["CSM", "Finance", "Product", "IT"]
    winner = None
    highest_score = max(csm_score, finance_score, product_score, it_score)

    if highest_score > 0:
        for team in priority:
            if (
                (team == "CSM" and csm_score == highest_score) or
                (team == "Finance" and finance_score == highest_score) or
                (team == "Product" and product_score == highest_score) or
                (team == "IT" and it_score == highest_score)
            ):
                winner = team
                break

    if winner == "CSM":
        doc.ticket_type = "General Inquiry"
        doc.agent_group = "Sabre CSM Team"
    elif winner == "Finance":
        doc.ticket_type = "Billing Issue"
        doc.agent_group = "Sabre Finance Team"
    elif winner == "Product":
        doc.ticket_type = "Technical Issue"
        doc.agent_group = "Sabre Product Team"
    elif winner == "IT":
        doc.ticket_type = "Technical Issue"
        doc.agent_group = "Sabre IT Support"
    else:
        doc.ticket_type = "General Inquiry"
        doc.agent_group = "Sabre Frontline Helpdesk"


# ========================================================
# 3️⃣ الجزء الثالث: قفل أمان سير العمل (يعمل مع كل عملية حفظ وتعديل)
# ========================================================
# بما أن حقل الـ Workflow State Field مربوط بحقل الـ status الأساسي
current_status = str(doc.get("status") or "").lower()
current_workflow = str(doc.get("workflow_state") or "").lower()

# إذا تحول أي من الحقلين إلى حل أو إغلاق، يتم تفعيل الحماية فوراً
if (current_status in ["resolved", "closed"] or current_workflow in ["resolved", "closed"]):
    if not doc.custom_subissue:
        frappe.throw(
            title="تنبيه جودة البيانات",
            msg="عذراً يا هندسة! بناءً على مخطط التدفق، يجب تغذية حقل <b>المشكلة الفرعية (Sub-Issue)</b> أولاً قبل تحويل المستند إلى حالة الحل أو الإغلاق سواء من الـ Desk أو الـ Portal."
        )

# ========================================================
# 4️⃣ الجزء الرابع: قفل أمان تحويل وتصعيد التذكرة (إجبارية Task)
# ========================================================
if current_workflow == "escalated":

    task_exists = frappe.db.exists("Task", {
        "custom_ticket": doc.name,
        "status": ["!=", "Cancelled"]
    })

    if not task_exists:
        frappe.throw(
            title="إجراء نظام صارم",
            msg="عذراً يا هندسة! بناءً على مخطط تدفق العمل لـ (Sabre Project)، <b>لا يمكن تصعيد التذكرة أو تحويلها</b> للفريق الفني دون إنشاء <u>مهمة (Task)</u> مرتبطة بها أولاً لتتبع التنفيذ الخلفي."
        )
